export default function(eleventyConfig) {
  // Pass through static assets
  eleventyConfig.addPassthroughCopy("public/css");
  eleventyConfig.addPassthroughCopy("public/js");
  eleventyConfig.addPassthroughCopy("public/brand");
  eleventyConfig.addPassthroughCopy("public/favicon.svg");
  // og.png is generated by screenshotting og.html (1200x630); pass the rendered PNG through.
  eleventyConfig.addPassthroughCopy("public/og.png");

  return {
    dir: {
      input: "public",
      output: "dist",
      includes: "_includes"
    },
    templateFormats: ["html", "njk", "md"],
    htmlTemplateEngine: "njk",
    markdownTemplateEngine: "njk"
  };
};
